// Setar o webhook de UMA instancia da Uazapi (uso manual/teste).
const UAZAPI_URL   = 'https://SEU-SERVIDOR.uazapi.com';
const UAZAPI_TOKEN = 'TOKEN_DA_INSTANCIA';
const WEBHOOK_URL  = 'https://SUBDOMINIO.divary.shop/api/crm/webhook';
const semBarra = (s) => (s && s.endsWith('/')) ? s.slice(0, -1) : s;

await this.helpers.httpRequest({
  method: 'POST',
  url: semBarra(UAZAPI_URL) + '/webhook',
  headers: { token: UAZAPI_TOKEN, 'Content-Type': 'application/json' },
  body: { enabled: true, url: WEBHOOK_URL, events: ['messages'] },
  json: true,
});
return [{ json: { ok: true, webhook: WEBHOOK_URL } }];
